<?php
$texte = "  Bonjour le Monde  ";

// Longueur et casse
echo strlen($texte) . "\n";          // 20
echo strtolower($texte) . "\n";      // bonjour le monde
echo strtoupper($texte) . "\n";      // BONJOUR LE MONDE
echo ucfirst("hello world") . "\n";  // Hello world
echo ucwords("hello world") . "\n";  // Hello World

// Nettoyage
echo trim($texte) . "\n";         // "Bonjour le Monde" (sans espaces)
echo ltrim($texte) . "\n";        // espaces gauche supprimés
echo str_pad("5", 3, "0", STR_PAD_LEFT) . "\n"; // 005

// Recherche et extraction
$email = "alice@example.com";
echo strpos($email, "@") . "\n";   // 5 (position du @)
echo substr($email, 0, 5) . "\n";  // alice
echo substr($email, 6) . "\n";    // example.com

// Remplacement
$phrase = "Chat noir mange souris";
echo str_replace("noir", "blanc", $phrase) . "\n";

// Découpage
$csv = "alice,bob,charlie";
$noms = explode(",", $csv);
print_r($noms);

// Test de contenu
echo str_contains($email, "@") ? "Valide\n" : "Invalide\n"; // PHP 8+
?>
```

