<?php
// sprintf : formater une chaîne (comme printf en C)
$nom = "Alice";
$score = 98.5;
$total = 100;

// %s = string, %d = entier, %.2f = float 2 décimales
$message = sprintf("%-10s : %3d/%-3d (%.1f%%)", $nom, (int)$score, $total, $score);
echo $message . "\n";  // Alice      :  98/100 (98.5%)

// Nombre formaté
echo number_format(1234567.89, 2, ',', ' ') . "\n";
// 1 234 567,89

// Date
echo date("d/m/Y H:i") . "\n";  // 15/01/2024 14:30

// Heredoc : chaîne multi-lignes avec interpolation
$html = <<<HTML
<h1>Bonjour $nom</h1>
<p>Score : $score</p>
HTML;
echo $html . "\n";

// Nowdoc : chaîne multi-lignes SANS interpolation
$sql = <<<'SQL'
SELECT * FROM users WHERE email = '$email'
SQL;
echo $sql . "\n";  // $email n'est pas remplacé
?>
```
